var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"생포했다던 침입자가 이 녀석인가?","JPN":"捕らえたという侵入者はそいつか？","ENG":"So is this the intruder you captured?","TWN":"逮捕的入侵者就是這傢伙嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"예. 침입 경로로 봐선 연구 중이던 아티팩트를 탈취할 속셈이었던 것 같습니다.","JPN":"はい。侵入経路からすると、研究中だったアーティファクトを奪るつもりだったようです。","ENG":"Yes. The infiltration route suggests that he was planning to steal the Artifact under study.","TWN":"是。從入侵路線來看，好像是想盜取研究中的人造神器。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"먼저 잡은 녀석도 그렇고 하나같이 튀는 옷차림이군.","JPN":"前に捕らえたヤツもそうだが、揃って派手な服装だな。","ENG":"He's dressed uniquely, just like the other one we captured.","TWN":"之前抓到的傢伙也是，裝扮都很顯眼啊。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"낯짝은 반반하게 생겨선 간이 부었어.","JPN":"ツラはいいが、ふてぶてしいヤツだ。","ENG":"He sure has guts for a pretty boy.","TWN":"長得弱不禁風的，膽子倒是不小。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러는 넌 뻔뻔한 성격만큼이나 멍청하게 생겼네.","JPN":"そういうお前は、見事なアホ面だな。","ENG":"And you sure are as stupid as you look.","TWN":"你倒是長得一副蠢樣，一看就厚顏無恥。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"테러리스트 잔당 주제에 아직도 군인 행세나 하는 건 쪽 팔리지 않냐?","JPN":"テロリストの残党のくせに軍人の振りをするなんて、恥ずかしくないか？","ENG":"Aren't you even a bit embarrassed to be playing soldier when you're nothing but a bunch of failed terrorists?","TWN":"不過是恐怖分子的殘黨，居然還擺著軍人的架子，你不覺得丟臉嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"큭......!","JPN":"くっ……！","ENG":"Ugh!","TWN":"哼……！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"이 방에는 정신 교란 재머가 설치되어 있다.","JPN":"この部屋には、精神を撹乱させる妨害電波発信機が設置されている。","ENG":"This room is installed with something we call the Mind Jammer.","TWN":"這個房間裝有精神干擾器。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"네 카운터 능력도 여기선 무용지물이란 소리야.","JPN":"つまり、お前のカウンター能力もここでは無用の長物ってことだ。","ENG":"In other words, your Counter abilities are useless here.","TWN":"也就是說，你的制裁者能力在這裡毫無用處。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"혼자 있는 시간 동안 무슨 소리를 해야 내가 기뻐할지 고민해 두는 게 좋을 거다.","JPN":"一人でいる間、何を話せば俺を喜ばせることができるか、考えておくんだな。","ENG":"While you're alone, you'd best think of what I want to hear from you.","TWN":"我勸你最好能夠說些讓我高興的事情，一個人乖乖待著想清楚吧。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐가 보안이 허술해? 그 홍차 폭탄, 기준이 너무 높잖아?","JPN":"セキュリティが甘い？　あの紅茶爆弾、基準が高すぎるだろ！","ENG":"So much for rubbish security. That Tea Bomb's standards are too high.","TWN":"什麼嘛，防守很鬆懈啊？那個紅茶炸彈標準也太高了吧！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 괜히 모건 할배 흉내내지 말고 하던 대로 죄다 박살내는 건데.","JPN":"こんな事になるなら、モーガンのジジイの真似なんかせずに、\\nいつも通りぶっ壊すんだった。","ENG":"If I knew it was going to be this hardcore, I would've just smashed everything to bits instead of trying to be sneaky like old man Morgan.","TWN":"早知道就不學摩根爺爺，照我一貫的方式全都幹掉就好了。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇. 불평은 살아나간 후에나 해야겠지.","JPN":"チッ。愚痴は生還してから、思いっきり言ってやる。","ENG":"Hmpf. I suppose I should save the rant for later, once I make it out of here alive.","TWN":"切，抱怨還是等活命之後再說吧。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그나저나 모건 할배가 이럴 때 빠져나갈 방법을 가르쳐 줬던 것 같은데......","JPN":"確かモーガンのジジイが、こういう時に抜け出す方法を教えてくれたような……","ENG":"Anyway... I'm pretty sure that Morgan taught me how to get out of a tight spot like this...","TWN":"不過，摩根爺爺好像教過我，這種時候逃跑的方法……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"에이, 신참. 볼륨 좀 낮춰.","JPN":"そこの新入り。声がでかい。","ENG":"Hey, noob boy. Turn down the volume, would ya?","TWN":"嘿，新人，把音量放低一點。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"방음도 잘 안 되는데 탈출 시도할 거라고 동네방네 광고할 일 있어?","JPN":"そんな大声で脱出しますって独り言を言ったら、ここのやつらに知られちゃうでしょ？","ENG":"You wanna advertise your escape attempt to the whole world?","TWN":"這裡的隔音可不好，你是想告訴所有人自己計畫逃跑嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"엉? 뭐야, 넌 또?","JPN":"ああん？　何だ、お前？","ENG":"Huh? What the... Who're you?","TWN":"啊？搞什麼，妳又是誰？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};